import { Grid, Typography, ToggleButton, ToggleButtonGroup } from '@mui/material';
import React, { useState } from 'react';
import { withStyles } from '@mui/styles';

const StyledToggle = withStyles({
    root: {
    color: '#00aeef',
    '&$selected': {
        color: 'white',
        background: '#00aeef',
    },
    '&:hover': {
        borderColor: '#00aeef',
        color: 'white',
        background: '#00aeef',
    },
    '&:hover$selected': {
        borderColor: '#00aeef',
        background: '#00aeef',
    },
    borderRadius: '20%',
    height: '50px',
    width: '50px',
    },
    selected: {},
})(ToggleButton);


function LengthOfSession({courseLength, setCourseLength}) {

    const [isClicked, setIsClicked] = useState(false);
    const Length = [30, 60, 90]

    const handleClick = (event) => {
        console.log({before: 'before', courseLength, isClicked});
		setCourseLength(Number(event.target.value));
        setIsClicked(!isClicked);
        console.log({after: 'after', courseLength, isClicked});
	}


  return (
    <div>
          <Typography variant='h3' mb={-2} mt={2} align='center'>
            Enter the length of your session:
          </Typography>

          <Grid container mt={2} mb={2} justifyContent='space-around' alignItems='center'>
          {
            Length.map((length) => {
                return (
                    <Grid item key={length}>
                        <ToggleButtonGroup>
                            <StyledToggle
                                value={length}
                                selected={length === courseLength}
                                onClick={handleClick}
                            >{`${length} minutes`}
                            </StyledToggle>
                        </ToggleButtonGroup>
                    </Grid>
                )
            })
          }
          </Grid>
    </div>
  )
}

export default LengthOfSession

