import React, {useState} from 'react';
import Button from '@mui/material/Button';
import Dialog from '@mui/material/Dialog';
import Divider from '@mui/material/Divider';
import AppBar from '@mui/material/AppBar';
import Toolbar from '@mui/material/Toolbar';
import IconButton from '@mui/material/IconButton';
import Typography from '@mui/material/Typography';
import CloseIcon from '@mui/icons-material/Close';
import Container from '@mui/material/Container';
import Stack from '@mui/material/Stack';
import { Link, useNavigate } from 'react-router-dom';

import Slide from '@mui/material/Slide';
import { Grid } from '@mui/material';
import axios from 'axios';
import useStore from '../../store';
import Payment from './Payment';

const backendURL = 'http://localhost:8126/';

const Transition = React.forwardRef(function Transition(props, ref) {
  return <Slide direction="up" ref={ref} {...props} />;
});

export default function PayPopUp(props) {
  const [open, setOpen] = React.useState(false);
  const {userName, isTeacher} = useStore();
  const navigate = useNavigate();

  async function bookThisCourse() {
    
    await axios.post(`${backendURL}booking/bookings`, {
      // date: props.date,
      // time: props.time,
      // couseName: props.
      // name, 
      date: props.selectedDateAndTime,
      profileImage: props.profileImage,
      pricePerGuest: props.pricePerGuest,
      numberOfGuests: props.guests,
      course: props.courseID,
      teacherID: props.owner,
      // address: props.courseAddress,
      // city: props.courseCity,
      // zipCode: props.courseZipcode,
      // studentFirstName: props.firstName,
      // studentLastName: props.lastName,
    });
    navigate(`/${isTeacher ? 'teachers' : 'students'}/${userName}`)
  }
  
  const handleClickOpen = () => {
    setOpen(true);
  };

  const handleClose = () => {
    setOpen(false);
  };

  return (
    <Container>
        {!(props.isRegistered) &&
        <Link to='/student-sign-up' style={{textDecoration: 'none'}}>
          <Button variant="outlined">Register to sign up</Button>
        </Link>}
        <Button 
          // disabled={!(props.isRegistered)} 
          variant="outlined" 
          onClick={handleClickOpen}>
          Pay
        </Button>
        <Dialog
          fullScreen
          open={open}
          onClose={handleClose}
          TransitionComponent={Transition}
        >
          <AppBar sx={{ position: 'relative' }}>
            <Toolbar>
              <Typography sx={{ ml: 2, flex: 1 }} variant="h6" component="div">
                Payment Method
              </Typography>
              <IconButton
                edge="start"
                color="inherit"
                onClick={handleClose}
                aria-label="close"
              >
                <CloseIcon />
              </IconButton>
            </Toolbar>
          </AppBar>
<Typography variant="h6" m={2}> Price Breakdown:</Typography>
              <Grid container>
                <Grid container p={2} justifyContent='left' direction='column'>
                <Grid item>
                    <Typography variant='h6'>
                      {`Course: ${props.courseTitle}`}
                    </Typography>
                  </Grid>
                  <Grid item>
                    <Typography variant='h6'>
                      {`Teacher: ${props.teacherFullName}`}
                    </Typography>
                  </Grid>
                  <Grid item>
                    <Typography variant='h6'>
                      {props.selectedDateAndTime.startDate}
                    </Typography>
                  </Grid>
                  <Grid item>
                    <Typography variant='h6'>
                    {props.selectedDateAndTime.startTime}
                    </Typography>
                  </Grid>
                </Grid>
                <Grid container p={2} justifyContent='right' direction='row' columnSpacing={2}>
                  <Stack direction='row' rowGap={2}>
                    <Typography variant='h6'>
                      Cost per guest:
                    </Typography>
                    <Typography variant='h6'>
                      ${props.pricePerGuest}
                    </Typography>
                  </Stack>
                </Grid>
                <Grid container p={2} justifyContent='right' columnSpacing={2}>
                  <Grid item>
                    <Typography variant='h6'>
                      Guests:
                    </Typography>
                  </Grid>
                  <Grid item>
                    <Typography variant='h6'>
                      {props.guests}
                    </Typography>
                  </Grid>
                  <Grid container p={2} justifyContent='right' columnSpacing={2}>
                    <Grid item>
                      <Typography variant='h6'>
                        ${props.total}
                      </Typography>
                    </Grid>
                    </Grid>
                    </Grid>
                </Grid>
                <Divider/>
                <Grid container p={2}>
                  <button type='hidden' onClick={bookThisCourse} > 
                    <Payment item={props} />
                  </button>
                </Grid>
                <Divider/>
        </Dialog>
    </Container>
  );
}
