import React from 'react';
import { Avatar, Card, Grid, Skeleton, Stack, Typography } from '@mui/material';
import Slider from "react-slick";
import "slick-carousel/slick/slick.css";
import "slick-carousel/slick/slick-theme.css";
import logo from '../../assets/Osmosis_Logo.png';
import "./SessionCard.css";

function SessionCard (props) {
  
  // PROPS INCLUDE: date / images / courseTitle / industry / tags / price / capacity / icon / firstName / lastName / address / zipCode / profileImage / city 

  const settings = {
    dots: true,
    infinite: false,
    speed: 500,
    slidesToShow: 1,
    slidesToScroll: 1,
  };
  
  return (
    // <LinkRouter to='/teachers/:userName/:course' style={{textDecoration:'none', color:'white'}}>
        <Card style={{ backgroundColor: "#00aeef"}}>

          <Slider {...settings}>
            <div>
            {
              props.icon === '0' ? <Typography>Loading...</Typography> : 
              <img src={props.images} className="carousel-image"/>
            }
            </div>
          </Slider>

          <Grid container>
          
            <Grid item xs={8}>
                <div className="card-title">
                  <Stack direction='column' alignItems='left'>
                    
                    <h6 className="industry">{props.courseTitle}</h6>
                    <Grid fullWidth item alignItems='left'>
					<Typography className='tags'>
						<Grid container direction='row' alignItems='center'>
            {/* WHEN NEWLY CREATED USER, THERE IS NO TAGS TO MAP THROUGH */}
							{ 
                props.tags?.map((tag, index) => {
									return (
												<Typography 
													variant='h5' 
													align='left'
													key={index} 
													id={index}
												>
													#{tag}&nbsp;
												</Typography>
									)
								})
              }
						</Grid>
					</Typography>
				</Grid>
                    
                    <Stack direction='row'>
                    {/* WHEN NEWLY CREATED USER THERE IS NO ICON TO DISPLAY */}
                      {/* <img src={require(`../../assets/icons/${props.icon}.png`)} alt={props.icon} style={{ marginLeft:'3%', width:'25px', height:'25px'}}/> */}
                      <h6 className="industry">{props.industry}</h6>
                    </Stack>

                  </Stack>
                </div>
            </Grid>

            <Grid item xs align='center' style={{paddingTop:'4%', color: 'white'}}>
              <Grid item>
              {
                props.icon === '0' ? <Typography>Loading...</Typography> : 
                <Avatar src={props.profileImage} />
              }
                <p className='name'> {props.firstName} {props.lastName}</p>
                <p className='tags'>{props.capacity} capacity</p>
                <p className='tags'>${props.price}/guest</p>
              </Grid>
            </Grid>

          </Grid>

          <hr />

          <Grid container className="more-info" align="center">
            
            <Grid item xs={6} style={{borderRight:'white solid 1px'}}>
              <Stack spacing={-3}>
                
                <Stack item>
                  <p>{props?.date?.split('', 3)}</p>
                </Stack>

                <Stack item>
                  <p>{props?.date?.substr(3).split(2023)}</p>
                </Stack>

                <Stack item>
                  <p>{props?.time}</p>
                </Stack>
                
              </Stack>
            </Grid>

            <Grid item xs={6}>
              <Stack spacing={-3} >

                <Stack item>
                  <p>{props.address}</p>
                </Stack>
              
                <Stack item>
                  <p>{props.city}, {props.zipCode}</p>
                </Stack>

              </Stack>
            </Grid>

          </Grid>

        </Card>

    // </LinkRouter>
  )
}

export default SessionCard;